  var f2Val: Float = 0.0f
  var f3Val: Double = 0.0
  var f4Val: Array[Byte] = Array.emptyByteArray
  var f5Val: String = ""
  var f6Val: Boolean = false
  var f7Val: Int = 0
  var f8Val: Int = 0
  var f9Val: Int = 0
  var f10Val: Long = 0L
  r.beginObject()
  while (r.hasNextField()) {
    r.readFieldName() match {
      case "f1" => f1Val = r.readUint64()
      case "f2" => f2Val = r.readFloat32()
      case "f3" => f3Val = r.readFloat64()
      case "f4" => f4Val = r.readBytes()
      case "f5" => f5Val = r.readString()
      case "f6" => f6Val = r.readBool()
      case "f7" => f7Val = r.readInt32()
      case "f8" => f8Val = r.readInt32()
      case "f9" => f9Val = r.readInt32()
      case "f10" => f10Val = r.readInt64()
      case _ => r.skip()
    }
  }
  r.endObject()
  Ten04(f1 = f1Val, f2 = f2Val, f3 = f3Val, f4 = f4Val, f5 = f5Val, f6 = f6Val, f7 = f7Val, f8 = f8Val, f9 = f9Val, f10 = f10Val)
}

val Ten04Codec = SpecCodec[Ten04](encode = writeTen04, decode = decodeTen04)

case class Ten05(
  f1: Array[Byte] = Array.emptyByteArray,
  f2: String = "",
  f3: Boolean = false,
  f4: Int = 0,
  f5: Int = 0,
  f6: Int = 0,
  f7: Long = 0L,
  f8: Long = 0L,
  f9: Long = 0L,
  f10: Long = 0L
)

def writeTen05(w: SpecWriter, obj: Ten05): Unit = {
  w.beginObject(10)
  w.writeField("f1"); w.writeBytes(obj.f1)
  w.writeField("f2"); w.writeString(obj.f2)
  w.writeField("f3"); w.writeBool(obj.f3)
  w.writeField("f4"); w.writeInt32(obj.f4)
  w.writeField("f5"); w.writeInt32(obj.f5)
  w.writeField("f6"); w.writeInt32(obj.f6)
  w.writeField("f7"); w.writeInt64(obj.f7)
  w.writeField("f8"); w.writeUint32(obj.f8)
  w.writeField("f9"); w.writeUint32(obj.f9)
  w.writeField("f10"); w.writeUint32(obj.f10)
  w.endObject()
}

def decodeTen05(r: SpecReader): Ten05 = {
  var f1Val: Array[Byte] = Array.emptyByteArray
  var f2Val: String = ""
  var f3Val: Boolean = false
  var f4Val: Int = 0
  var f5Val: Int = 0
  var f6Val: Int = 0
  var f7Val: Long = 0L
  var f8Val: Long = 0L
  var f9Val: Long = 0L
  var f10Val: Long = 0L
  r.beginObject()
  while (r.hasNextField()) {
    r.readFieldName() match {
      case "f1" => f1Val = r.readBytes()
      case "f2" => f2Val = r.readString()
      case "f3" => f3Val = r.readBool()
      case "f4" => f4Val = r.readInt32()
      case "f5" => f5Val = r.readInt32()
      case "f6" => f6Val = r.readInt32()
      case "f7" => f7Val = r.readInt64()
      case "f8" => f8Val = r.readUint32().toLong
      case "f9" => f9Val = r.readUint32().toLong
      case "f10" => f10Val = r.readUint32().toLong
      case _ => r.skip()
    }
  }
  r.endObject()
  Ten05(f1 = f1Val, f2 = f2Val, f3 = f3Val, f4 = f4Val, f5 = f5Val, f6 = f6Val, f7 = f7Val, f8 = f8Val, f9 = f9Val, f10 = f10Val)
}

val Ten05Codec = SpecCodec[Ten05](encode = writeTen05, decode = decodeTen05)
